refsection.programlisting:

global GROCERDIR
// load the model small:
load(GROCERDIR+'data\small.dat')
// load the database small_db:
load(GROCERDIR+'data\small_db.dat')
// set the bounds:
bounds('1990q1','2005q4');
// In the small model, estimate by ols with ARMA(2,1) residuals the equation td_p3m_d1,
// save the estimated coefficients into the small model tlist
// and store into tlist rp3m_d1 the whole estimation results:
[small,rp3m_d1]=olsarmamod(small,small_db,'td_p3m_d1',[0 0 ],0,'save=%t');
